import React from 'react';

const FirstColumn = () => {
  return (
    <div className="flex flex-col h-full bg-neutral-900 p-2 gap-4">
      {/* Logo/Avatar do usuário */}
      <div className="w-12 h-12 bg-neutral-700 rounded-lg flex items-center justify-center border border-neutral-600">
        <span className="text-white text-lg font-semibold">UR</span>
      </div>

      {/* Espaço flexível */}
      <div className="flex-1"></div>

      {/* Avatar do usuário na parte inferior */}
      <div className="relative">
        <div className="w-8 h-8 rounded-full overflow-hidden border-2 border-neutral-600">
          <img 
            src="https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?ixlib=rb-1.2.1&ixid=eyJhcHBfaWQiOjEyMDd9&auto=format&fit=facearea&facepad=2&w=256&h=256&q=80" 
            alt="User Avatar" 
            className="w-full h-full object-cover"
          />
        </div>
        {/* Indicador verde de status online */}
        <div className="absolute -bottom-0.5 -right-0.5 w-4 h-4 bg-green-500 rounded-full border-2 border-neutral-800"></div>
      </div>
    </div>
  );
};

export default FirstColumn;
